/** Retourne la définition de grille pour une ville */
export function getCityGridDefinition(cityId: CityId): CityGridDefinition {
  return CITY_GRID_DEFINITIONS[cityId];
}

/** Retourne uniquement les expansions jouables (hors blockers) */
export function getPlayableExpansions(cityId: CityId): ExpansionDef[] {
  return CITY_GRID_DEFINITIONS[cityId].expansions.filter(
    e => e.type !== 'blocker'
  );
}

/** Retourne les expansions de la zone principale (Y >= 0) */
export function getMainCityExpansions(cityId: CityId): ExpansionDef[] {
  return CITY_GRID_DEFINITIONS[cityId].expansions.filter(e => e.y >= 0);
}
